unit lipdecide;

{$mode fpc}

interface

uses
  globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

uses
  Math;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  maxAbs: real;
  exponent: Int64;
  scale: real;
  scaledA, scaledB: Int64;
begin
  maxAbs := Abs(A);
  if Abs(B) > maxAbs then
    maxAbs := Abs(B);

  if maxAbs = 0.0 then
    exit(EQ);

  exponent := Floor(Log10(maxAbs));
  scale := Power(10.0, 5 - exponent);

  scaledA := Round(A * scale);
  scaledB := Round(B * scale);

  if scaledA < scaledB then
    exit(LT);
  if scaledA > scaledB then
    exit(GT);
  exit(EQ);
end;

function RealLT(A, B: real): boolean; inline;
begin
  RealLT := REALCOMPARE(A, B) = LT;
end;

function RealGT(A, B: real): boolean; inline;
begin
  RealGT := REALCOMPARE(A, B) = GT;
end;

function RealEQ(A, B: real): boolean; inline;
begin
  RealEQ := REALCOMPARE(A, B) = EQ;
end;

function RealLE(A, B: real): boolean; inline;
begin
  RealLE := (REALCOMPARE(A, B) <> GT);
end;

function RealGE(A, B: real): boolean; inline;
begin
  RealGE := (REALCOMPARE(A, B) <> LT);
end;

type
  TPoint = record
    X, Y: real;
  end;

function Pt(Index: integer): TPoint; inline;
begin
  Pt.X := globals.X[Index];
  Pt.Y := globals.Y[Index];
end;

function PtEq(const A, B: TPoint): boolean; inline;
begin
  PtEq := RealEQ(A.X, B.X) and RealEQ(A.Y, B.Y);
end;

function Dist(const A, B: TPoint): real; inline;
var
  dx, dy: real;
begin
  dx := B.X - A.X;
  dy := B.Y - A.Y;
  Dist := Sqrt(Sqr(dx) + Sqr(dy));
end;

function TriangleArea(const A, B, C: TPoint): real; inline;
begin
  TriangleArea :=
    Abs(A.X * (B.Y - C.Y) + B.X * (C.Y - A.Y) + C.X * (A.Y - B.Y)) / 2.0;
end;

function ClampCos(Value: real): real; inline;
begin
  if RealGT(Value, 1.0) then
    exit(1.0);
  if RealLT(Value, -1.0) then
    exit(-1.0);
  exit(Value);
end;

function AngleAtVertex(const A, V, B: TPoint; var Defined: boolean): real;
var
  ux, uy, vx, vy: real;
  du, dv: real;
  cosv: real;
begin
  ux := A.X - V.X;
  uy := A.Y - V.Y;
  vx := B.X - V.X;
  vy := B.Y - V.Y;

  du := Sqrt(Sqr(ux) + Sqr(uy));
  dv := Sqrt(Sqr(vx) + Sqr(vy));

  if RealEQ(du, 0.0) or RealEQ(dv, 0.0) then
  begin
    Defined := false;
    exit(0.0);
  end;

  cosv := (ux * vx + uy * vy) / (du * dv);
  cosv := ClampCos(cosv);
  Defined := true;
  AngleAtVertex := ArcCos(cosv);
end;

function MaxReal(A, B: real): real; inline;
begin
  if RealGT(A, B) then
    exit(A);
  exit(B);
end;

function MaxReal3(A, B, C: real): real; inline;
begin
  MaxReal3 := MaxReal(A, MaxReal(B, C));
end;

function MinEnclosingCircleRadius3(const A, B, C: TPoint): real;
var
  a2, b2, c2: real;
  area: real;
  maxSide2, sumOther2: real;
  sideA, sideB, sideC: real;
begin
  a2 := Sqr(B.X - C.X) + Sqr(B.Y - C.Y);
  b2 := Sqr(A.X - C.X) + Sqr(A.Y - C.Y);
  c2 := Sqr(A.X - B.X) + Sqr(A.Y - B.Y);

  maxSide2 := MaxReal3(a2, b2, c2);
  area := TriangleArea(A, B, C);

  if RealEQ(area, 0.0) then
    exit(Sqrt(maxSide2) / 2.0);

  if RealEQ(maxSide2, a2) then
    sumOther2 := b2 + c2
  else if RealEQ(maxSide2, b2) then
    sumOther2 := a2 + c2
  else
    sumOther2 := a2 + b2;

  if RealGE(maxSide2, sumOther2) then
    exit(Sqrt(maxSide2) / 2.0);

  sideA := Sqrt(a2);
  sideB := Sqrt(b2);
  sideC := Sqrt(c2);
  MinEnclosingCircleRadius3 := (sideA * sideB * sideC) / (4.0 * area);
end;

function QuadrantOf(const P: TPoint): integer;
var
  sx, sy: COMPTYPE;
begin
  sx := REALCOMPARE(P.X, 0.0);
  sy := REALCOMPARE(P.Y, 0.0);

  if (sx <> LT) and (sy <> LT) then
    exit(1); // I:  x >= 0, y >= 0
  if (sx = LT) and (sy <> LT) then
    exit(2); // II: x < 0,  y >= 0
  if (sx <> GT) and (sy = LT) then
    exit(3); // III: x <= 0, y < 0
  exit(4);   // IV: x > 0,  y < 0
end;

function DistancePointToLine(const P, A, B: TPoint): real;
var
  num, den: real;
begin
  den := Sqrt(Sqr(B.Y - A.Y) + Sqr(B.X - A.X));
  if RealEQ(den, 0.0) then
    exit(Dist(P, A));
  num := Abs((B.Y - A.Y) * P.X - (B.X - A.X) * P.Y + B.X * A.Y - B.Y * A.X);
  DistancePointToLine := num / den;
end;

function LIC1: boolean;
var
  i: integer;
begin
  for i := 1 to NUMPOINTS - 1 do
    if RealGT(Dist(Pt(i), Pt(i + 1)), PARAMETERS.LENGTH1) then
      exit(true);
  exit(false);
end;

function LIC2: boolean;
var
  i: integer;
begin
  if NUMPOINTS < 3 then
    exit(false);
  for i := 1 to NUMPOINTS - 2 do
    if RealGT(MinEnclosingCircleRadius3(Pt(i), Pt(i + 1), Pt(i + 2)), PARAMETERS.RADIUS1) then
      exit(true);
  exit(false);
end;

function LIC3: boolean;
var
  i: integer;
  a, v, b: TPoint;
  ang: real;
  defined: boolean;
  lo, hi: real;
begin
  if NUMPOINTS < 3 then
    exit(false);
  lo := globals.PI - PARAMETERS.EPSILON;
  hi := globals.PI + PARAMETERS.EPSILON;
  for i := 1 to NUMPOINTS - 2 do
  begin
    a := Pt(i);
    v := Pt(i + 1);
    b := Pt(i + 2);
    if PtEq(a, v) or PtEq(b, v) then
      continue;
    ang := AngleAtVertex(a, v, b, defined);
    if not defined then
      continue;
    if RealLT(ang, lo) or RealGT(ang, hi) then
      exit(true);
  end;
  exit(false);
end;

function LIC4: boolean;
var
  i: integer;
begin
  if NUMPOINTS < 3 then
    exit(false);
  for i := 1 to NUMPOINTS - 2 do
    if RealGT(TriangleArea(Pt(i), Pt(i + 1), Pt(i + 2)), PARAMETERS.AREA1) then
      exit(true);
  exit(false);
end;

function LIC5: boolean;
var
  startIdx, k: integer;
  seen: array[1..4] of boolean;
  q, count: integer;
begin
  for startIdx := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    for k := 1 to 4 do
      seen[k] := false;
    for k := startIdx to startIdx + PARAMETERS.Q_PTS - 1 do
    begin
      q := QuadrantOf(Pt(k));
      seen[q] := true;
    end;
    count := 0;
    for k := 1 to 4 do
      if seen[k] then
        Inc(count);
    if count > PARAMETERS.QUADS then
      exit(true);
  end;
  exit(false);
end;

function LIC6: boolean;
var
  i: integer;
begin
  for i := 1 to NUMPOINTS - 1 do
    if RealLT(Pt(i + 1).X - Pt(i).X, 0.0) then
      exit(true);
  exit(false);
end;

function LIC7: boolean;
var
  startIdx, midIdx: integer;
  firstP, lastP: TPoint;
  d: real;
begin
  if NUMPOINTS < 3 then
    exit(false);
  for startIdx := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    firstP := Pt(startIdx);
    lastP := Pt(startIdx + PARAMETERS.N_PTS - 1);

    if PtEq(firstP, lastP) then
    begin
      for midIdx := startIdx + 1 to startIdx + PARAMETERS.N_PTS - 2 do
        if RealGT(Dist(Pt(midIdx), firstP), PARAMETERS.DIST) then
          exit(true);
    end
    else
    begin
      for midIdx := startIdx + 1 to startIdx + PARAMETERS.N_PTS - 2 do
      begin
        d := DistancePointToLine(Pt(midIdx), firstP, lastP);
        if RealGT(d, PARAMETERS.DIST) then
          exit(true);
      end;
    end;
  end;
  exit(false);
end;

function LIC8: boolean;
var
  i, j: integer;
begin
  if NUMPOINTS < 3 then
    exit(false);
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    if RealGT(Dist(Pt(i), Pt(j)), PARAMETERS.LENGTH1) then
      exit(true);
  end;
  exit(false);
end;

function LIC9: boolean;
var
  i, j, k: integer;
begin
  if NUMPOINTS < 5 then
    exit(false);
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    if RealGT(MinEnclosingCircleRadius3(Pt(i), Pt(j), Pt(k)), PARAMETERS.RADIUS1) then
      exit(true);
  end;
  exit(false);
end;

function LIC10: boolean;
var
  i, j, k: integer;
  a, v, b: TPoint;
  ang: real;
  defined: boolean;
  lo, hi: real;
begin
  if NUMPOINTS < 5 then
    exit(false);
  lo := globals.PI - PARAMETERS.EPSILON;
  hi := globals.PI + PARAMETERS.EPSILON;
  for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    j := i + PARAMETERS.C_PTS + 1;
    k := j + PARAMETERS.D_PTS + 1;
    a := Pt(i);
    v := Pt(j);
    b := Pt(k);
    if PtEq(a, v) or PtEq(b, v) then
      continue;
    ang := AngleAtVertex(a, v, b, defined);
    if not defined then
      continue;
    if RealLT(ang, lo) or RealGT(ang, hi) then
      exit(true);
  end;
  exit(false);
end;

function LIC11: boolean;
var
  i, j, k: integer;
begin
  if NUMPOINTS < 5 then
    exit(false);
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    if RealGT(TriangleArea(Pt(i), Pt(j), Pt(k)), PARAMETERS.AREA1) then
      exit(true);
  end;
  exit(false);
end;

function LIC12: boolean;
var
  i, j: integer;
begin
  if NUMPOINTS < 3 then
    exit(false);
  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    j := i + PARAMETERS.G_PTS + 1;
    if RealLT(Pt(j).X - Pt(i).X, 0.0) then
      exit(true);
  end;
  exit(false);
end;

function LIC13: boolean;
var
  i, j: integer;
  d: real;
  foundGT, foundLT: boolean;
begin
  if NUMPOINTS < 3 then
    exit(false);
  foundGT := false;
  foundLT := false;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    d := Dist(Pt(i), Pt(j));
    if RealGT(d, PARAMETERS.LENGTH1) then
      foundGT := true;
    if RealLT(d, PARAMETERS.LENGTH2) then
      foundLT := true;
    if foundGT and foundLT then
      exit(true);
  end;
  exit(false);
end;

function LIC14: boolean;
var
  i, j, k: integer;
  r: real;
  foundNotInR1, foundInR2: boolean;
begin
  if NUMPOINTS < 5 then
    exit(false);
  foundNotInR1 := false;
  foundInR2 := false;
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    r := MinEnclosingCircleRadius3(Pt(i), Pt(j), Pt(k));
    if RealGT(r, PARAMETERS.RADIUS1) then
      foundNotInR1 := true;
    if RealLE(r, PARAMETERS.RADIUS2) then
      foundInR2 := true;
    if foundNotInR1 and foundInR2 then
      exit(true);
  end;
  exit(false);
end;

function LIC15: boolean;
var
  i, j, k: integer;
  a: real;
  foundGT, foundLT: boolean;
begin
  if NUMPOINTS < 5 then
    exit(false);
  foundGT := false;
  foundLT := false;
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    a := TriangleArea(Pt(i), Pt(j), Pt(k));
    if RealGT(a, PARAMETERS.AREA1) then
      foundGT := true;
    if RealLT(a, PARAMETERS.AREA2) then
      foundLT := true;
    if foundGT and foundLT then
      exit(true);
  end;
  exit(false);
end;

procedure DECIDE;
var
  i, j: integer;
  rowAll: boolean;
  allFuv: boolean;
begin
  CMV[1] := LIC1;
  CMV[2] := LIC2;
  CMV[3] := LIC3;
  CMV[4] := LIC4;
  CMV[5] := LIC5;
  CMV[6] := LIC6;
  CMV[7] := LIC7;
  CMV[8] := LIC8;
  CMV[9] := LIC9;
  CMV[10] := LIC10;
  CMV[11] := LIC11;
  CMV[12] := LIC12;
  CMV[13] := LIC13;
  CMV[14] := LIC14;
  CMV[15] := LIC15;

  for i := 1 to 15 do
    for j := 1 to 15 do
      if i <> j then
        case LCM[i, j] of
          NOTUSED: PUM[i, j] := true;
          ANDD: PUM[i, j] := CMV[i] and CMV[j];
          ORR: PUM[i, j] := CMV[i] or CMV[j];
        end;

  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
    begin
      FUV[i] := true;
      continue;
    end;

    rowAll := true;
    for j := 1 to 15 do
      if not PUM[i, j] then
      begin
        rowAll := false;
        break;
      end;
    FUV[i] := rowAll;
  end;

  allFuv := true;
  for i := 1 to 15 do
    if not FUV[i] then
    begin
      allFuv := false;
      break;
    end;

  LAUNCH := allFuv;
end;

end.
